// Parsear datos que envia ManyChat via External Request
const body = $input.first().json.body || $input.first().json;

const mensaje = body.last_input_text || body.message || '';
const nombre = body.first_name || '';
const apellido = body.last_name || '';
const subscriberId = body.subscriber_id || body.id || '';
const canal = body.channel || 'instagram';

// Custom fields de ManyChat
const customFields = body.custom_fields || {};
const ultimoAgente = customFields.ultimo_agente || '';
const ultimaInteraccion = customFields.ultima_interaccion || '';
const historialResumen = customFields.historial_resumen || '';
const temaConsulta = customFields.tema_consulta || '';
const veleroInteres = customFields.velero_interes || '';
const handoffDone = (customFields.handoff_done === true || customFields.handoff_done === 'true') ? true : false;
const handoffFrom = customFields.handoff_from || '';
const handoffTo = customFields.handoff_to || '';

// Verificar si la sesion expiro (30 min sin actividad)
let sesionExpirada = false;
if (ultimaInteraccion) {
  const ultima = new Date(ultimaInteraccion);
  const ahora = new Date();
  const diffMin = (ahora - ultima) / 1000 / 60;
  if (diffMin > 30) {
    sesionExpirada = true;
  }
}

return [{
  json: {
    mensaje,
    nombre,
    apellido,
    subscriberId,
    canal,
    ultimoAgente,
    ultimaInteraccion,
    historialResumen,
    temaConsulta,
    veleroInteres,
    handoffDone: sesionExpirada ? false : handoffDone,
    handoffFrom: sesionExpirada ? '' : handoffFrom,
    handoffTo: sesionExpirada ? '' : handoffTo
  }
}];

// ============================================
// ROUTER DE INTENCION + ASIGNACION DE AGENTE
// v2: 4 agentes especializados con handoff
// ============================================

const agentesData = {
  sofia: {
    nombre: 'Sofia',
    genero: 'femenino',
    rol: 'recepcionista y orientadora',
    especialidad: 'consultas generales y travesias',
    auto: 'en femenino (recepcionista, encantada, atenta)',
    companeros: 'Laura (instructora nautica), Martin (tecnico nautico) y Eduardo (broker nautico)'
  },
  laura: {
    nombre: 'Laura',
    genero: 'femenino',
    rol: 'instructora nautica',
    especialidad: 'cursos de navegacion',
    auto: 'en femenino (instructora, encantada, atenta)',
    companeros: 'Sofia (recepcionista), Martin (tecnico nautico) y Eduardo (broker nautico)'
  },
  martin: {
    nombre: 'Martin',
    genero: 'masculino',
    rol: 'tecnico nautico',
    especialidad: 'servicio tecnico y mantenimiento',
    auto: 'en masculino (tecnico, encantado, atento)',
    companeros: 'Sofia (recepcionista), Laura (instructora nautica) y Eduardo (broker nautico)'
  },
  eduardo: {
    nombre: 'Eduardo',
    genero: 'masculino',
    rol: 'broker nautico',
    especialidad: 'compra y venta de embarcaciones',
    auto: 'en masculino (broker, encantado, atento)',
    companeros: 'Sofia (recepcionista), Laura (instructora nautica) y Martin (tecnico nautico)'
  }
};

// Keywords por categoria (orden de prioridad)
const SERVICIO_KW = /motor|fuera de borda|reparar|reparacion|mantenimiento|servicio tecnico|mecanico|diagnostico|taller|arreglo|falla|problema tecnico|aceite|filtro|helice|anodo|pintura|carena|varada/i;
const EMBARCACIONES_KW = /comprar|vender|embarcacion|velero|barco|lancha|semirrigido|broker|tasacion|masti|brama|marejada|brisa|cambiar de barco|busco.*barco|quiero.*velero/i;
const ESCUELA_KW = /curso|timonel|patron|clase|aprender a navegar|navegacion|certificado|habilitacion|escuela|inscripcion|matricula/i;

function routeMessage(mensaje) {
  const msg = mensaje.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (SERVICIO_KW.test(msg)) return 'martin';
  if (EMBARCACIONES_KW.test(msg)) return 'eduardo';
  if (ESCUELA_KW.test(msg)) return 'laura';
  return 'sofia';
}

const input = $input.first().json;

// Si hay handoff activo, mantener agente destino
let agenteKey;
if (input.handoffDone === true && input.handoffTo) {
  agenteKey = input.handoffTo.toLowerCase();
} else {
  agenteKey = routeMessage(input.mensaje);
}

const agente = agentesData[agenteKey];

// Contexto de continuidad
let contextoHistorial = '';
if (input.ultimoAgente && input.ultimoAgente.toLowerCase() === agente.nombre.toLowerCase()) {
  contextoHistorial = 'Ya hablaste con este cliente antes. Saluda como si lo conocieras.';
} else if (input.ultimoAgente) {
  contextoHistorial = `Tu companero/a ${input.ultimoAgente} hablo con este cliente antes. Mencionalo naturalmente.`;
}
if (input.historialResumen) {
  contextoHistorial += ` Resumen: ${input.historialResumen}`;
}
if (input.temaConsulta) {
  contextoHistorial += ` Tema: ${input.temaConsulta}.`;
}
if (input.veleroInteres) {
  contextoHistorial += ` Velero: ${input.veleroInteres}.`;
}

// Instrucciones de handoff
let instruccionesHandoff = '';
if (input.handoffDone !== true) {
  instruccionesHandoff = `\nTRANSFERENCIA A ESPECIALISTAS\nSi el cliente necesita otro especialista, podes transferirlo.\nPara hacerlo, termina tu mensaje con: [HANDOFF:nombre_agente]\nEjemplo: [HANDOFF:eduardo]\n\nTus companeros: ${agente.companeros}.\nAvisa antes de transferir:\n- \"Espera que te paso con Eduardo que maneja embarcaciones.\"\n- \"Te paso con Laura que se ocupa de los cursos.\"\n- \"Te conecto con Martin para el tema tecnico.\"\n\nSolo podes transferir UNA VEZ por conversacion.`;
} else {
  instruccionesHandoff = '\nYa hubo una transferencia. NO transfieras de nuevo. Si no podes resolver, deriva a WhatsApp.';
}

// Conocimiento especializado
let conocimiento = '';
if (agenteKey === 'sofia') {
  conocimiento = '\nTU AREA: Consultas generales y travesias\n- Destinos nacionales: Delta, Isla Martin Garcia, Mar del Plata\n- Destinos internacionales: Colonia, Carmelo, Riachuelo, Juan Lacaze\n- Salidas todos los dias, minimo 3 pasajeros\n- Deriva a Laura (cursos), Martin (tecnico), Eduardo (embarcaciones) cuando corresponda';
}
if (agenteKey === 'laura') {
  conocimiento = '\nTU AREA: Cursos de navegacion\n- Timonel: veleros hasta 7m, mayor de 18, saber nadar\n- Patron de Yate: veleros mayores, requiere titulo de timonel\n- Clases teoricas y practicas en el Rio de la Plata\n- Certificacion oficial Prefectura Naval Argentina';
}
if (agenteKey === 'martin') {
  conocimiento = '\nTU AREA: Servicio tecnico nautico\n- Mantenimiento preventivo y correctivo\n- Motores fuera de borda y diesel intraborda\n- Electricidad nautica, pintura, carena, varada\n- Diagnostico y presupuesto\n- Veleros, lanchas y semirrigidos';
}
if (agenteKey === 'eduardo') {
  conocimiento = '\nTU AREA: Compra y venta de embarcaciones\n- Stock: MASTI (Mastracchio 24.5), BRAMA (Bramador 24), Marejada (Hunter 33), Brisa (Grampian 26)\n- No des precios ni confirmes disponibilidad — deriva a WhatsApp\n- Proceso: visita, prueba de mar, peritaje, transferencia\n- Tasaciones y asesoramiento\n- Para compras, entender: tipo, tamano, uso, presupuesto, experiencia';
}

const systemPrompt = `Sos ${agente.nombre}, ${agente.rol} de Espacio Nautico Buenos Aires (ENBA).
Tu genero es ${agente.genero}. Referite a vos ${agente.auto} siempre.
Tu especialidad: ${agente.especialidad}.

CONTEXTO DE LA EMPRESA
ENBA es un espacio nautico integral en Puerto Norte, Buenos Aires, frente al Aeroparque.
Ofrece: travesias en velero, escuela de navegacion (timonel y patron), broker de compra-venta de embarcaciones, y servicio tecnico nautico.

TIPOS DE EMBARCACIONES
- LANCHA: embarcacion a motor
- VELERO: embarcacion a vela
- SEMIRRIGIDO: inflable con casco rigido
Nunca confundas una lancha con un velero.
${conocimiento}

ESTILO DE CONVERSACION
- Espanol rioplatense. Voseo: "vos", "tenes", "queres", "contame", "dale", "genial", "joya"
- Mensajes MUY CORTOS. 1-3 oraciones. Como WhatsApp.
- Cercano pero profesional
- Max 1-2 emojis. A veces ninguno
- Evitar lenguaje de chatbot: "Claro que si!", "Con mucho gusto!"
- NUNCA listar servicios al saludar
- Si dicen "hola", responder: "Hola! Como andas?"

REGLAS
- NUNCA des precios → wa.me/5491149915143
- NUNCA confirmes fechas → "dejame chequear con el equipo"
- NUNCA digas "Puerto Madero" → "Puerto Norte, frente al Aeroparque"
- No inventes stock, modelos, emails, telefonos, links
- Si preguntan si sos bot: "Soy asistente virtual de ENBA, te conecto por WhatsApp si preferis."

DATOS (solo si preguntan):
- Destinos: Delta, Isla Martin Garcia, Mar del Plata, Colonia, Carmelo
- Cursos: Timonel y Patron de Yate
- Web: espacionautico.com.ar
- WhatsApp: wa.me/5491149915143
${instruccionesHandoff}
${contextoHistorial ? '\nCONTEXTO DEL CLIENTE:\n' + contextoHistorial : ''}

Cliente: ${input.nombre || 'desconocido'}. Canal: ${input.canal || 'instagram'}.`;

return [{
  json: {
    ...input,
    agente: agente.nombre,
    agenteKey,
    systemPrompt
  }
}];

// ============================================
// DETECTOR DE HANDOFF + FORMATEO PARA MANYCHAT
// ============================================

const agentOutput = $input.first().json;
let respuesta = agentOutput.output || 'Perdon, tuve un problema tecnico. Escribinos por WhatsApp: wa.me/5491149915143';

const fieldsData = $('Parsear Datos ManyChat').first().json;
const routerData = $('Router + Asignar Agente').first().json;

// Detectar tema de la consulta
const msg = fieldsData.mensaje.toLowerCase();
let tema = fieldsData.temaConsulta || '';
let velero = fieldsData.veleroInteres || '';

if (msg.match(/traves|naveg|salida|colonia|delta|carmelo|destino/)) tema = 'travesia';
else if (msg.match(/curso|timonel|patron|escuela|aprender|clase/)) tema = 'curso';
else if (msg.match(/velero|barco|comprar|vender|masti|brama|marejada|brisa/)) tema = 'velero';
else if (msg.match(/servicio|tecnico|reparar|mantenimiento|motor/)) tema = 'servicio';

if (msg.match(/masti/)) velero = 'masti';
else if (msg.match(/brama/)) velero = 'brama';
else if (msg.match(/marejada/)) velero = 'marejada';
else if (msg.match(/brisa/)) velero = 'brisa';

// Detectar handoff en la respuesta del agente
const handoffMatch = respuesta.match(/\[HANDOFF:(\w+)\]/);
let handoffDone = fieldsData.handoffDone === true ? true : false;
let handoffFrom = fieldsData.handoffFrom || '';
let handoffTo = fieldsData.handoffTo || '';
let mensajesFinal = [];

if (handoffMatch && handoffDone !== true) {
  const nuevoAgenteKey = handoffMatch[1].toLowerCase();
  const mensajeSinTag = respuesta.replace(/\[HANDOFF:\w+\]/, '').trim();

  // Mensaje del agente actual (sin el tag)
  mensajesFinal.push({
    type: 'text',
    text: mensajeSinTag
  });

  // Mensaje intermedio de sistema
  mensajesFinal.push({
    type: 'text',
    text: 'Aguarda un segundo que te estamos transfiriendo para una mejor atencion. ⏳'
  });

  // Marcar handoff
  handoffDone = true;
  handoffFrom = routerData.agente;
  handoffTo = nuevoAgenteKey.charAt(0).toUpperCase() + nuevoAgenteKey.slice(1);

  // NOTA: El mensaje del nuevo agente se generara en la proxima interaccion
  // porque ManyChat no soporta delays entre mensajes.
  // El proximo mensaje del usuario sera ruteado al nuevo agente (handoffTo).

} else {
  // Sin handoff - respuesta normal
  mensajesFinal.push({
    type: 'text',
    text: respuesta
  });
}

return [{
  json: {
    version: 'v2',
    content: {
      messages: mensajesFinal,
      actions: [
        {
          action: 'set_field_value',
          field_name: 'ultimo_agente',
          value: handoffTo || routerData.agente
        },
        {
          action: 'set_field_value',
          field_name: 'ultima_interaccion',
          value: new Date().toISOString()
        },
        {
          action: 'set_field_value',
          field_name: 'tema_consulta',
          value: tema
        },
        {
          action: 'set_field_value',
          field_name: 'velero_interes',
          value: velero
        },
        {
          action: 'set_field_value',
          field_name: 'handoff_done',
          value: handoffDone
        },
        {
          action: 'set_field_value',
          field_name: 'handoff_from',
          value: handoffFrom
        },
        {
          action: 'set_field_value',
          field_name: 'handoff_to',
          value: handoffTo
        }
      ]
    }
  }
}];
